{
  "mode": "method",
  "tests": [
    {
      "name": "valid_user_login",
      "input": {
        "username": "testuser",
        "password": "securepassword"
      },
      "output": {
        "status": "success",
        "token": "valid_token_string"
      },
      "notes": "Validates successful login with correct credentials."
    },
    {
      "name": "invalid_user_login",
      "input": {
        "username": "testuser",
        "password": "wrongpassword"
      },
      "output": {
        "status": "error",
        "message": "Invalid credentials"
      },
      "notes": "Tests response for incorrect password."
    },
    {
      "name": "remove_group_tables",
      "input": {
        "operation": "remove",
        "tables": ["Group", "GroupMembership"]
      },
      "output": {
        "status": "success",
        "message": "Group tables removed"
      },
      "notes": "Ensures group-related tables are successfully removed."
    },
    {
      "name": "single_schema_usage",
      "input": {
        "schema": "identity"
      },
      "output": {
        "status": "success",
        "message": "Single schema in use"
      },
      "notes": "Validates that only the identity schema is being used."
    },
    {
      "name": "crypto_dependency_removal",
      "input": {
        "dependency": "Crypto.JS"
      },
      "output": {
        "status": "success",
        "message": "Crypto.JS dependency removed"
      },
      "notes": "Checks that deprecated Crypto.JS is no longer in use."
    },
    {
      "name": "postman_collection_update",
      "input": {
        "api": "UserService",
        "tests": 5
      },
      "output": {
        "status": "success",
        "message": "Postman collection updated with 5 tests"
      },
      "notes": "Validates that the Postman collection has been expanded."
    },
    {
      "name": "edge_case_empty_username",
      "input": {
        "username": "",
        "password": "securepassword"
      },
      "output": {
        "status": "error",
        "message": "Username cannot be empty"
      },
      "notes": "Tests the system's response to an empty username."
    },
    {
      "name": "edge_case_empty_password",
      "input": {
        "username": "testuser",
        "password": ""
      },
      "output": {
        "status": "error",
        "message": "Password cannot be empty"
      },
      "notes": "Tests the system's response to an empty password."
    }
  ],
  "assumptions": "All services are running and accessible.",
  "notes": "Ensure that the database is in a clean state before running tests."
}
